// Import necessary modules from ethers.js
const { ethers } = require("ethers");

// Function to connect to the Ethereum network
async function connectToNetwork() {
    // Connect to an Ethereum provider (e.g., MetaMask)
    const provider = new ethers.providers.Web3Provider(window.ethereum);
    
    // Request access to the user's Ethereum accounts
    await provider.send("eth_requestAccounts", []);
    
    // Create a signer from the provider
    const signer = provider.getSigner();
    
    return { provider, signer };
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, functionName, params) {
    // Connect to the network and get the signer
    const { provider, signer } = await connectToNetwork();
    
    // Create a new instance of the contract
    const contract = new ethers.Contract(contractAddress, abi, signer);
    
    // Call the function on the smart contract with user-provided parameters
    try {
        const tx = await contract[functionName](...params);
        console.log("Transaction sent:", tx.hash);
        
        // Wait for the transaction to be mined
        const receipt = await tx.wait();
        console.log("Transaction confirmed:", receipt.transactionHash);
    } catch (error) {
        console.error("Error interacting with contract:", error);
    }
}

